import { KeyValue as KeyValueRoot, type KeyValueProps } from "./key-value";
import type { KeyValueLayout, KeyValueVariant } from "./key-value-context";
import { KeyValueItem, type KeyValueItemProps } from "./key-value-item";

const KeyValue = Object.assign(KeyValueRoot, { Item: KeyValueItem });

export { KeyValue, type KeyValueProps, type KeyValueLayout };
export { KeyValueItem, type KeyValueItemProps, type KeyValueVariant };

"use client";

import { useMemo, type ComponentPropsWithRef, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { KeyValueContext, type KeyValueLayout } from "./key-value-context";

export interface KeyValueProps extends ComponentPropsWithRef<"dl"> {
  layout?: KeyValueLayout;
  bordered?: boolean;
  children: ReactNode;
}

export function KeyValue({
  layout = "horizontal",
  bordered = false,
  children,
  className,
  ref,
  ...props
}: KeyValueProps) {
  const contextValue = useMemo(() => ({ layout, bordered }), [layout, bordered]);

  return (
    <KeyValueContext value={contextValue}>
      <dl ref={ref} className={cn("flex flex-col", className)} {...props}>
        {children}
      </dl>
    </KeyValueContext>
  );
}

"use client";

import type { ComponentPropsWithRef, ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useKeyValueContext, type KeyValueLayout, type KeyValueVariant } from "./key-value-context";

export interface KeyValueItemProps extends ComponentPropsWithRef<"div"> {
  label: ReactNode;
  value: ReactNode;
  variant?: KeyValueVariant;
  layout?: KeyValueLayout;
  bordered?: boolean;
}

const keyValueItemVariants = cva("", {
  variants: {
    layout: {
      horizontal: "flex justify-between items-center",
      vertical: "flex flex-col gap-1",
    },
    bordered: {
      true: "py-4 border-b border-border last:border-b-0",
      false: "",
    },
  },
  defaultVariants: { layout: "horizontal", bordered: false },
});

const valueVariants = cva("", {
  variants: {
    variant: {
      default: "font-bold text-foreground",
      warning: "font-bold text-warning",
      info: "font-mono text-foreground",
      success: "font-bold text-success",
      error: "font-bold text-destructive",
    },
    bordered: { true: "text-xs", false: "" },
  },
  defaultVariants: { variant: "default", bordered: false },
});

export function KeyValueItem({
  label,
  value,
  variant = "default",
  className,
  ref,
  layout: layoutProp,
  bordered: borderedProp,
  ...rest
}: KeyValueItemProps) {
  const ctx = useKeyValueContext();
  const layout = layoutProp ?? ctx.layout;
  const bordered = borderedProp ?? ctx.bordered;

  return (
    <div
      ref={ref}
      className={cn(keyValueItemVariants({ layout, bordered }), className)}
      {...rest}
    >
      <dt className={cn("text-muted-foreground", bordered ? "text-xs" : "text-sm")}>{label}</dt>
      <dd className={valueVariants({ variant, bordered })}>{value}</dd>
    </div>
  );
}

"use client";

import { createContext, useContext } from "react";

export type KeyValueLayout = "horizontal" | "vertical";
export type KeyValueVariant = "default" | "warning" | "info" | "success" | "error";

interface KeyValueContextValue {
  layout: KeyValueLayout;
  bordered: boolean;
}

const KeyValueContext = createContext<KeyValueContextValue | undefined>(undefined);

function useKeyValueContext(): KeyValueContextValue {
  const context = useContext(KeyValueContext);
  if (context === undefined) {
    throw new Error("KeyValue.Item must be used within KeyValue");
  }
  return context;
}

export { KeyValueContext, useKeyValueContext };
